const input = $json;

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizeRequestedItems(value) {
  if (Array.isArray(value)) {
    return value.map((item) => ({
      request_item_key: clean(item?.request_item_key),
      category: clean(item?.category),
      weight_range: clean(item?.weight_range),
      sex: clean(item?.sex),
      quantity: clean(item?.quantity),
      intent_type: clean(item?.intent_type),
      status: clean(item?.status),
      notes: clean(item?.notes),
    }));
  }
  return [];
}

return [
  {
    json: {
      action: clean(input.action),
      order_id: clean(input.order_id),
      customer_name: clean(input.customer_name),
      customer_phone: clean(input.customer_phone),
      customer_channel: clean(input.customer_channel),
      customer_language: clean(input.customer_language),
      order_source: clean(input.order_source),
      requested_category: clean(input.requested_category),
      requested_weight_range: clean(input.requested_weight_range),
      requested_sex: clean(input.requested_sex),
      requested_quantity: clean(input.requested_quantity),
      quoted_total: clean(input.quoted_total),
      pig_id: clean(input.pig_id),
      unit_price: clean(input.unit_price),
      collection_location: clean(input.collection_location),
      notes: clean(input.notes),
      payment_method: clean(input.payment_method),
      reason: clean(input.reason),
      changed_by: clean(input.changed_by) || "Order Steward",
      conversation_id: clean(input.conversation_id),
      contact_id: clean(input.contact_id),
      account_id: clean(input.account_id),
      requested_items: normalizeRequestedItems(input.requested_items),
      send_quote_if_ready: input.send_quote_if_ready === true || clean(input.send_quote_if_ready).toLowerCase() === "true",
      created_from_intake: input.created_from_intake === true || clean(input.created_from_intake).toLowerCase() === "true",
      intake_id: clean(input.intake_id),
    }
  }
];

const item = $json || {};

const body = {};

const orderId = String(item.order_id || "").trim();
const changedBy = String(item.changed_by || "").trim() || "Sam";

if (!orderId) {
  throw new Error("order_id is required for update_order.");
}

if (item.requested_quantity !== undefined && item.requested_quantity !== null && String(item.requested_quantity).trim() !== "") {
  body.requested_quantity = item.requested_quantity;
}

if (item.requested_category !== undefined && item.requested_category !== null && String(item.requested_category).trim() !== "") {
  body.requested_category = String(item.requested_category).trim();
}

if (item.requested_weight_range !== undefined && item.requested_weight_range !== null && String(item.requested_weight_range).trim() !== "") {
  body.requested_weight_range = String(item.requested_weight_range).trim();
}

if (item.requested_sex !== undefined && item.requested_sex !== null && String(item.requested_sex).trim() !== "") {
  body.requested_sex = String(item.requested_sex).trim();
}

if (item.collection_location !== undefined && item.collection_location !== null && String(item.collection_location).trim() !== "") {
  body.collection_location = String(item.collection_location).trim();
}

if (item.notes !== undefined && item.notes !== null && String(item.notes).trim() !== "") {
  body.notes = String(item.notes).trim();
}

const pm = String(item.payment_method || "").trim();
if (pm === "Cash" || pm === "EFT") {
  body.payment_method = pm;
}

body.changed_by = changedBy;

const updatableFieldCount =
  (body.requested_quantity !== undefined ? 1 : 0) +
  (body.requested_category !== undefined ? 1 : 0) +
  (body.requested_weight_range !== undefined ? 1 : 0) +
  (body.requested_sex !== undefined ? 1 : 0) +
  (body.collection_location !== undefined ? 1 : 0) +
  (body.notes !== undefined ? 1 : 0) +
  (body.payment_method !== undefined ? 1 : 0);

if (updatableFieldCount === 0) {
  throw new Error("No non-empty order fields were provided for update_order.");
}

return [
  {
    json: {
      ...item,
      order_id: orderId,
      patch_body: body
    }
  }
];

const item = $json || {};

return [
  {
    json: {
      success: item.success === true,
      action: "update_order",
      order_id: item.order_id || "",
      message: item.message || "",
      updated_fields: Array.isArray(item.updated_fields) ? item.updated_fields : [],
      changed_by: item.changed_by || "",
      auto_quote: item.auto_quote || null
    }
  }
];

const createResp = $json || {};
const normalized = $('Code - Normalize Order Payload').item.json || {};
const orderId = createResp.order_id || "";
return [{
  json: {
    create_success: createResp.success ?? false,
    create_message: createResp.message || "",
    order_id: orderId,
    requested_items: Array.isArray(normalized.requested_items) ? normalized.requested_items : [],
    changed_by: normalized.changed_by || "Sam",
    cancel_order_if_no_matches: true
  }
}];

const raw = $json || {};
const normalized = $('Code - Normalize Order Payload').first()?.json || {};
const fallbackOrderId = String(normalized.order_id || '').trim();

const order = raw.order;
const ok = raw.success === true && order && String(order.order_id || '').trim() !== '';

function slimLine(L) {
  if (!L || typeof L !== 'object') return {};
  return {
    order_line_id: L.order_line_id,
    pig_id: L.pig_id,
    sale_category: L.sale_category,
    weight_band: L.weight_band,
    sex: L.sex,
    line_status: L.line_status
  };
}

const lineList = Array.isArray(raw.lines) ? raw.lines : [];
const activeFromLines = lineList.filter(function (L) {
  return L && String(L.line_status || '') !== 'Cancelled';
}).length;
const o = ok ? order : {};
const activeLineCount =
  typeof o.active_line_count === 'number'
    ? o.active_line_count
    : typeof o.active_line_count === 'string' && o.active_line_count !== '' && !isNaN(Number(o.active_line_count))
      ? Number(o.active_line_count)
      : activeFromLines;

const existing_order_context = ok
  ? {
      order: {
        order_id: o.order_id,
        order_status: o.order_status,
        approval_status: o.approval_status,
        payment_status: o.payment_status,
        customer_name: o.customer_name,
        requested_category: o.requested_category,
        requested_weight_range: o.requested_weight_range,
        requested_sex: o.requested_sex,
        requested_quantity: o.requested_quantity,
        collection_date: o.collection_date,
        collection_location: o.collection_location,
        line_count: o.line_count,
        active_line_count: activeLineCount,
        line_count_includes_cancelled: true,
        payment_method: o.payment_method || '',
        notes: o.notes
      },
      lines: lineList.map(slimLine)
    }
  : null;

const orderId = ok ? String(o.order_id || '') : fallbackOrderId;
const msg = ok
  ? 'Order context retrieved.'
  : String(raw.error || raw.message || 'Order context fetch failed.').slice(0, 500);

return [
  {
    json: {
      success: ok,
      action: 'get_order_context',
      order_id: orderId,
      message: msg,
      order_context_fetch_ok: ok,
      existing_order_context: existing_order_context
    }
  }
];

const raw = $json || {};
const normalized = $('Code - Normalize Order Payload').first()?.json || {};

const ok = raw.success === true;
const lookupStatus = String(raw.lookup_status || '').trim();
const orderContext = raw.order_context && typeof raw.order_context === 'object'
  ? raw.order_context
  : null;
const matches = Array.isArray(raw.matches) ? raw.matches : [];
const orderId = String(raw.order_id || normalized.order_id || '').trim();

let msg = String(raw.message || raw.error || '').trim();
if (!msg && Array.isArray(raw.errors) && raw.errors.length > 0) {
  msg = String(raw.errors[0] || '').trim();
}
if (!msg) {
  msg = ok ? 'Active customer order lookup completed.' : 'Active customer order lookup failed.';
}

return [
  {
    json: {
      success: ok,
      action: 'get_active_customer_order_context',
      order_id: orderId,
      message: msg.slice(0, 500),
      active_order_context_fetch_ok: ok && lookupStatus === 'single_match' && orderContext !== null,
      lookup_status: lookupStatus || (ok ? 'unknown' : 'error'),
      match_count: Number(raw.match_count || 0),
      active_order_context: orderContext,
      active_order_matches: matches,
      lookup_inputs: {
        order_id: normalized.order_id || '',
        conversation_id: normalized.conversation_id || '',
        customer_phone: normalized.customer_phone || ''
      }
    }
  }
];

const raw = $json || {};
const normalized = $('Code - Normalize Order Payload').first()?.json || {};
const ok = raw.success === true;
let msg = String(raw.message || raw.error || '').trim();
if (!msg && Array.isArray(raw.errors) && raw.errors.length > 0) msg = String(raw.errors[0] || '').trim();
if (!msg) msg = ok ? 'Quote generated successfully.' : 'Quote generation failed.';

return [{
  json: {
    success: ok,
    action: 'generate_quote',
    order_id: String(raw.order_id || normalized.order_id || '').trim(),
    message: msg.slice(0, 500),
    document_id: raw.document_id || '',
    document_type: raw.document_type || 'Quote',
    document_ref: raw.document_ref || '',
    payment_ref: raw.payment_ref || '',
    version: raw.version || '',
    file_name: raw.file_name || '',
    google_drive_file_id: raw.google_drive_file_id || '',
    google_drive_url: raw.google_drive_url || '',
    subtotal_ex_vat: raw.subtotal_ex_vat,
    vat_amount: raw.vat_amount,
    total: raw.total,
    valid_until: raw.valid_until || '',
    backend_success: ok,
    backend_error: ok ? '' : msg.slice(0, 500)
  }
}];

const raw = $json || {};
const normalized = $('Code - Normalize Order Payload').first()?.json || {};
const ok = raw.success === true;
let msg = String(raw.message || raw.error || '').trim();
if (!msg && Array.isArray(raw.errors) && raw.errors.length > 0) msg = String(raw.errors[0] || '').trim();
if (!msg) msg = ok ? 'Quote sent successfully.' : 'Quote send failed.';

return [{
  json: {
    success: ok,
    action: 'send_latest_quote',
    order_id: String(raw.order_id || normalized.order_id || '').trim(),
    message: msg.slice(0, 500),
    document_id: raw.document_id || '',
    document_type: raw.document_type || 'Quote',
    document_ref: raw.document_ref || '',
    document_status: raw.document_status || '',
    conversation_id: raw.conversation_id || normalized.conversation_id || '',
    delivery_webhook_sent: raw.delivery_webhook_sent === true,
    backend_success: ok,
    backend_error: ok ? '' : msg.slice(0, 500)
  }
}];

const createResp = $("HTTP - Create With Lines Order").item.json || {};
const sendResp = $json || {};
const ok = sendResp.success === true;
let msg = String(sendResp.message || sendResp.error || '').trim();
if (!msg && Array.isArray(sendResp.errors) && sendResp.errors.length > 0) msg = String(sendResp.errors[0] || '').trim();
if (!msg) msg = ok ? 'Quote sent successfully.' : 'Quote send failed.';

return [{
  json: {
    ...createResp,
    quote_send: {
      success: ok,
      action: 'send_latest_quote',
      order_id: String(sendResp.order_id || createResp.order_id || '').trim(),
      message: msg.slice(0, 500),
      document_id: sendResp.document_id || '',
      document_type: sendResp.document_type || 'Quote',
      document_ref: sendResp.document_ref || '',
      document_status: sendResp.document_status || '',
      conversation_id: sendResp.conversation_id || $("Code - Normalize Order Payload").item.json.conversation_id || '',
      delivery_webhook_sent: sendResp.delivery_webhook_sent === true,
      backend_success: ok,
      backend_error: ok ? '' : msg.slice(0, 500),
      skipped: sendResp.skipped === true,
      reason: sendResp.reason || ''
    }
  }
}];
